export type StoreCategory =
  | "restaurant"
  | "salon"
  | "doctor"
  | "gym"
  | "electronics"
  | "pharmacy"
  | "packers"
  | "cafe"
  | "dentist"
  | "school";

// ── Business Type System ──────────────────────────────────────────────
// Determines which tabs and sections a store detail page shows,
// based on the kind of business it is.

export type BusinessType = "restaurant" | "product_store" | "service_provider";

export interface TabConfig {
  id: string;
  label: string;
}

/** Classify a store into a business type using its category string. */
export function getBusinessType(category: string): BusinessType {
  const cat = category.toLowerCase();
  if (cat.includes("restaurant")) return "restaurant";
  if (cat.includes("cafe")) return "restaurant"; // cafes share the restaurant layout (Menu tab)
  if (
    cat.includes("electronics") ||
    cat.includes("pharmacy") ||
    cat.includes("medical") ||
    cat.includes("grocery")
  )
    return "product_store";
  // salon, gym/fitness, dental, beauty, logistics, education, venue, etc.
  return "service_provider";
}

/** Build the ordered tab list for a store based on its business type. */
export function getBusinessTabs(store: StoreData): TabConfig[] {
  const type = getBusinessType(store.category);

  switch (type) {
    case "restaurant": {
      // Restaurants & Cafes: Overview → Menu → [Products] → Reviews
      const tabs: TabConfig[] = [
        { id: "overview", label: "Overview" },
        { id: "menu", label: "Menu" },
      ];
      if (store.products.length > 0)
        tabs.push({ id: "products", label: "Products" });
      tabs.push({ id: "reviews", label: "Reviews" });
      return tabs;
    }
    case "product_store": {
      // Electronics, Pharmacy, Grocery: Overview → [Services] → Products → Reviews
      const tabs: TabConfig[] = [{ id: "overview", label: "Overview" }];
      if (store.services.length > 0)
        tabs.push({ id: "services", label: "Services" });
      tabs.push({ id: "products", label: "Products" });
      tabs.push({ id: "reviews", label: "Reviews" });
      return tabs;
    }
    case "service_provider":
    default: {
      // Salons, Gyms, Dental, Beauty, Packers, School, Venue: Overview → Services → [Products] → Reviews
      const tabs: TabConfig[] = [
        { id: "overview", label: "Overview" },
        { id: "services", label: "Services" },
      ];
      if (store.products.length > 0)
        tabs.push({ id: "products", label: "Products" });
      tabs.push({ id: "reviews", label: "Reviews" });
      return tabs;
    }
  }
}

/** Human-readable label for the business type (used in overview headings). */
export function getBusinessTypeLabel(category: string): string {
  const type = getBusinessType(category);
  switch (type) {
    case "restaurant": return "Menu & Food";
    case "product_store": return "Products & Store";
    case "service_provider": return "Services & Pricing";
  }
}

